#[async_trait]
impl<R: AnalyticsReportProjectionRepository> AnalyticsReportEventHandler for AnalyticsReportProjector<R> {

    async fn on_created(&self, event: AnalyticsReportCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = AnalyticsReportProjection::new(
            event.id,
            event.report_name,
            event.report_type,
            event.description,
            event.parameters,
            event.format,
            event.generated_by,
            event.generated_at,
            event.expires_at,
            event.file_path,
            event.file_size,
            event.status,
            event.download_count,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: AnalyticsReportUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.report_name = event.report_name;
            projection.report_type = event.report_type;
            projection.description = event.description;
            projection.parameters = event.parameters;
            projection.format = event.format;
            projection.generated_by = event.generated_by;
            projection.generated_at = event.generated_at;
            projection.expires_at = event.expires_at;
            projection.file_path = event.file_path;
            projection.file_size = event.file_size;
            projection.status = event.status;
            projection.download_count = event.download_count;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: AnalyticsReportDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

